import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is a subnet mask?", a: "A subnet mask is a 32-bit number that divides an IP address into its network and host portions. Written in dotted-decimal notation (e.g., 255.255.255.0) or CIDR notation (/24). Bits set to 1 identify the network; bits set to 0 identify the host. Common masks: /24 = 255.255.255.0 (254 usable hosts), /16 = 255.255.0.0 (65,534 hosts), /8 = 255.0.0.0 (16M hosts)." },
  { q: "What is CIDR notation?", a: "CIDR (Classless Inter-Domain Routing) notation appends the number of network bits to the IP address after a slash (e.g., 192.168.1.0/24). The prefix length (/24) tells you how many of the 32 bits define the network. /24 = 24 network bits, 8 host bits. CIDR replaced the older class-based system (Class A/B/C) and allows more flexible subnet sizing." },
  { q: "What is the difference between network address and broadcast address?", a: "The network address (first IP in a subnet) identifies the subnet itself and cannot be assigned to any device. The broadcast address (last IP) is used to send data to all devices on the subnet simultaneously - also unassignable. For a /24 subnet: x.x.x.0 = network address, x.x.x.255 = broadcast address, x.x.x.1 through x.x.x.254 = 254 usable host addresses." },
  { q: "How many usable hosts does each CIDR prefix have?", a: "Usable hosts = 2^(32-) - 2. Common values: /24 = 254, /25 = 126, /26 = 62, /27 = 30, /28 = 14, /29 = 6, /30 = 2 (for point-to-point links), /31 = 0 in traditional subnetting (RFC 3021 allows 2), /32 = single host route. The - accounts for network and broadcast addresses." },
  { q: "What are private IP address ranges?", a: "RFC 1918 defines three private IP ranges: 10.0.0.0/8 (16.7M addresses), 172.16.0.0/12 (1M addresses), 192.168.0.0/16 (65,536 addresses). These are not routable on the public internet and require NAT for internet access. Home routers typically use 192.168.0.0/24 or 192.168.1.0/24. Corporate networks often use 10.0.0.0/8 or 172.16.0.0/12." },
  { q: "What is subnetting and why is it done?", a: "Subnetting divides a large network into smaller sub-networks. Benefits: improved security (isolates network segments), reduced broadcast traffic, efficient IP address usage, and simplified network management. Example: dividing a /24 (254 hosts) into four /26 subnets (62 hosts each) for different departments, each isolated from the others." },
  { q: "How do I calculate if two IPs are on the same subnet?", a: "Apply the subnet mask to both IP addresses using a bitwise AND operation. If both results are identical, the IPs are on the same subnet. Example: 192.168.1.50 AND 255.255.255.0 = 192.168.1.0. 192.168.1.100 AND 255.255.255.0 = 192.168.1.0. Same result - same subnet. This is exactly what this calculator does automatically." },
  { q: "What is a /30 subnet used for?", a: "A /30 subnet has 4 total addresses, 2 usable hosts - perfect for point-to-point links between two routers. It wastes minimal IP space while providing the required two endpoints. Common in WAN links and router interconnects. A /31 can also be used for P2P links (RFC 3021) with 2 usable addresses and no wasted network/broadcast addresses." },
];

const CIDR_TABLE = [
  ["/8", "255.0.0.0", "16,777,216", "16,777,214"],
  ["/16", "255.255.0.0", "65,536", "65,534"],
  ["/20", "255.255.240.0", "4,096", "4,094"],
  ["/24", "255.255.255.0", "256", "254"],
  ["/25", "255.255.255.128", "128", "126"],
  ["/26", "255.255.255.192", "64", "62"],
  ["/27", "255.255.255.224", "32", "30"],
  ["/28", "255.255.255.240", "16", "14"],
  ["/29", "255.255.255.248", "8", "6"],
  ["/30", "255.255.255.252", "4", "2"],
  ["/32", "255.255.255.255", "1", "1 (host route)"],
];

function ipToInt(ip: string): number {
  return ip.split(".").reduce((acc, octet) => (acc << 8) + parseInt(octet), 0) >>> 0;
}
function intToIp(n: number): string {
  return [(n >>> 24) & 255, (n >>> 16) & 255, (n >>> 8) & 255, n & 255].join(".");
}
function intToBinary(n: number): string {
  return [(n >>> 24) & 255, (n >>> 16) & 255, (n >>> 8) & 255, n & 255].map(o => o.toString(2).padStart(8, "0")).join(".");
}

export default function SubnetCalculator() {
  const [ip, setIp] = useState("192.168.1.0");
  const [cidr, setCidr] = useState(24);

  const ipInt = ipToInt(ip);
  const maskInt = cidr === 0 ? 0 : (0xFFFFFFFF << (32 - cidr)) >>> 0;
  const networkInt = (ipInt & maskInt) >>> 0;
  const broadcastInt = (networkInt | (~maskInt >>> 0)) >>> 0;
  const firstHost = networkInt + 1;
  const lastHost = broadcastInt - 1;
  const totalHosts = Math.pow(2, 32 - cidr);
  const usableHosts = Math.max(0, totalHosts - 2);

  const isValidIp = /^(\d{1,3}\.){3}\d{1,3}$/.test(ip) && ip.split(".").every(o => parseInt(o) >= 0 && parseInt(o) <= 255);

  return (
    <>
      <SEOHead
        title="Free Subnet Calculator Online - Calculate Network Address and Usable Hosts Instantly | CalcHive"
        description="Free online subnet calculator. Calculate network address, broadcast address and usable hosts from any IPv4 CIDR instantly. 100% free for network engineers and students, no signup needed."
        canonical="/subnet-calculator"
        keywords="free subnet calculator, IPv4 subnet calculator free online, CIDR subnet calculator free, network address calculator free, usable hosts calculator free"
        category="Tech Tools"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-slate-600 dark:text-slate-400 bg-slate-100 dark:bg-slate-800/50 px-3 py-1 rounded-full mb-4 inline-block">Tools</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Subnet Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free subnet calculator to calculate network address, broadcast address, and usable hosts from any IPv4 CIDR. This IPv4 subnet calculator free online also works as a CIDR subnet calculator free, network address calculator free, and usable hosts calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid sm:grid-cols-2 gap-4 mb-8">
            <div>
              <label className="text-sm font-semibold text-foreground block mb-2">IP Address</label>
              <input type="text" value={ip} onChange={e => setIp(e.target.value)} placeholder="192.168.1.0" className="w-full px-3 py-2.5 rounded-xl border border-input bg-background font-mono text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all" />
            </div>
            <div>
              <label className="text-sm font-semibold text-foreground block mb-2">CIDR Prefix Length (/{cidr})</label>
              <input type="range" min={0} max={32} value={cidr} onChange={e => setCidr(Number(e.target.value))} className="w-full h-2 rounded-full appearance-none cursor-pointer accent-primary mt-3" />
              <div className="flex justify-between text-xs text-muted-foreground mt-1"><span>/0</span><span>/{cidr}</span><span>/32</span></div>
            </div>
          </div>
          {isValidIp ? (
            <motion.div key={`${ip}-${cidr}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
              <div className="bg-gradient-to-br from-slate-600 to-slate-800 rounded-2xl p-6 mb-4 text-center shadow-lg">
                <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Usable Host Addresses</p>
                <p className="text-6xl font-black text-white tracking-tight" data-testid="result-hosts">{usableHosts.toLocaleString()}</p>
                <p className="text-white/70 text-sm mt-1">/{cidr} - {intToIp(maskInt)} subnet mask</p>
              </div>
              <div className="grid grid-cols-2 gap-3 mb-3">
                {[
                  { label: "Network Address", value: intToIp(networkInt) },
                  { label: "Broadcast Address", value: intToIp(broadcastInt) },
                  { label: "First Usable Host", value: usableHosts > 0 ? intToIp(firstHost) : "N/A" },
                  { label: "Last Usable Host", value: usableHosts > 0 ? intToIp(lastHost) : "N/A" },
                  { label: "Total Addresses", value: totalHosts.toLocaleString() },
                  { label: "Subnet Mask", value: intToIp(maskInt) },
                ].map(({ label, value }) => (
                  <div key={label} className="bg-accent/60 border border-border rounded-xl p-3 hover:shadow-sm transition-shadow">
                    <p className="text-xs text-muted-foreground font-medium mb-0.5">{label}</p>
                    <p className="text-sm font-extrabold text-foreground font-mono">{value}</p>
                  </div>
                ))}
              </div>
              <div className="bg-accent/60 border border-border rounded-xl p-3">
                <p className="text-xs text-muted-foreground font-medium mb-1">Subnet Mask (Binary)</p>
                <p className="text-xs font-mono text-foreground break-all">{intToBinary(maskInt)}</p>
              </div>
            </motion.div>
          ) : <p className="text-center text-muted-foreground py-4">Enter a valid IPv4 address (e.g. 192.168.1.0)</p>}
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Subnet Network and Broadcast Address for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Subnetting uses bitwise AND operations to separate the network and host portions of an IP address. The subnet mask applied to the IP address gives the network address; inverting the mask and OR-ing gives the broadcast address. All addresses between are valid hosts.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Network Address = IP AND Subnet Mask</p>
            <p>Broadcast = Network OR (NOT Subnet Mask)</p>
            <p>Usable Hosts = 2^(32 - prefix) - 2</p>
            <p>First Host = Network Address + 1</p>
            <p>Last Host = Broadcast Address - 1</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How to Find Usable Hosts From Any IPv4 CIDR</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["CIDR", "Subnet Mask", "Total Addresses", "Usable Hosts"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {CIDR_TABLE.map(([c, mask, total, usable]) => (
                  <tr key={c} className={`hover:bg-muted/30 ${c === `/${cidr}` ? "bg-slate-50 dark:bg-slate-800/30 font-semibold" : ""}`}>
                    <td className="py-2.5 px-4 font-bold text-slate-600 dark:text-slate-400 font-mono">{c}</td>
                    <td className="py-2.5 px-4 font-mono text-muted-foreground">{mask}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{total}</td>
                    <td className="py-2.5 px-4 font-bold text-foreground">{usable}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free IP Subnet Tool for Network Engineers and Students</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free network tool on any device to check addresses, host ranges, and subnet details without downloads or signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/subnet-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


